		origCost := dispatch.Assigns[i].Cost

		if !dispatch.Assigns[i].AddShip(total_ship+jj, oris[jj], dess[jj]) {
			continue
		}
		dispatch.Assigns[i].GenRoute()
		newCost := dispatch.Assigns[i].Cost
		if newCost >= 0 {
			delta := newCost - origCost
			if delta < bestDelta {
				bestDelta = delta
				bestIdx = i
			}
		}
		// undo the trial insertion
		dispatch.Assigns[i].RemoveShip(total_ship + jj)
		dispatch.Assigns[i].GenRoute()
	}

	if bestIdx != -1 {
		// apply the best insertion permanently
		dispatch.Assigns[bestIdx].AddShip(total_ship+jj, oris[jj], dess[jj])
		dispatch.Assigns[bestIdx].GenRoute()
	} else {
		// fallback: start a new assign
